                    buttons.add(new ButtonBox(workLabel, px, py + bi*gameStep, Math.max(86, cmd.width-36), gameBh, "Use the built Scrap Workbench: process scrap, repair clothes, assemble parts, or fabricate EMM machinery.", () -> activateCommand(workLabel)));
