    ZoneType auditZoneType() {
        ZoneType[] values = ZoneType.values();
        if (values.length == 0) return ZoneType.TRASH_WARREN;
        auditZoneTypeIndex = Math.floorMod(auditZoneTypeIndex, values.length);
        return values[auditZoneTypeIndex];
    }
    void setAuditZoneTypeIndex(int idx) {
        ZoneType[] values = ZoneType.values();
        if (values.length == 0) return;
        auditZoneTypeIndex = Math.floorMod(idx, values.length);
        auditZoneDropdownOpen = false;
        int visible = Math.max(3, Math.min(5, values.length));
        if (auditZoneTypeIndex < auditZoneButtonScroll) auditZoneButtonScroll = auditZoneTypeIndex;
        if (auditZoneTypeIndex >= auditZoneButtonScroll + visible) auditZoneButtonScroll = auditZoneTypeIndex - visible + 1;
        auditZoneButtonScroll = Math.max(0, Math.min(Math.max(0, values.length - visible), auditZoneButtonScroll));
        regenerateSectorAuditWorld("select audit zone type");
    }

    int containedAuditZoneButtonStart(int visible) {
        ZoneType[] values = ZoneType.values();
        if (values.length == 0) return 0;
        int v = Math.max(1, Math.min(visible, values.length));
        if (auditZoneTypeIndex < auditZoneButtonScroll) auditZoneButtonScroll = auditZoneTypeIndex;
        if (auditZoneTypeIndex >= auditZoneButtonScroll + v) auditZoneButtonScroll = auditZoneTypeIndex - v + 1;
        auditZoneButtonScroll = Math.max(0, Math.min(Math.max(0, values.length - v), auditZoneButtonScroll));
        return auditZoneButtonScroll;
    }

    void scrollAuditZoneButtons(int delta) {
        ZoneType[] values = ZoneType.values();
        if (values.length == 0) return;
        int visible = Math.max(3, Math.min(5, values.length));
        auditZoneButtonScroll = Math.max(0, Math.min(Math.max(0, values.length - visible), auditZoneButtonScroll + delta));
        repaint();
    }


    WorldSetupSettings auditSettings() {
        WorldSetupSettings s = WorldSetupSettings.standard();
        s.zoneSize = Math.max(0, Math.min(3, auditZoneSizeIndex));
        s.zoneDensity = Math.max(0, Math.min(3, auditZoneDensityIndex));
        // Zone Audit is a placement-density inspection surface; use a crowded
        // civilian baseline instead of the former sparse testing override so NPC
        // fields, bottlenecks, and doorway blocking are visible during audit.
        s.npcDensity = 3;
        s.simulationAge = 0;
        return s;
    }

    void regenerateSectorAuditWorld(String reason) {
        long previousSeed = auditSeed;
        if (reason != null && reason.toLowerCase(Locale.ROOT).contains("reroll")) auditSeed = System.currentTimeMillis() ^ (auditSeed * 31L);
        WorldSetupSettings previousSettings = WorldGenerationApi.settings().copy();
        try {
            WorldSetupSettings auditSettings = auditSettings();
            WorldGenerationApi.setActiveSettings(auditSettings);
            Dimension d = WorldGenerationApi.zoneSliceSize(auditSeed);
            World w = new World(auditSeed, d.width, d.height);
            w.zoneType = auditZoneType();
            w.sewerLayer = auditSewerLayer;
            w.hiveName = "Audit Arcology";
            w.sectorName = "Zone Audit";
            w.zoneName = "Zone Audit " + w.zoneType.label + (w.sewerLayer ? " Sewer" : " Floor");
            w.zoneHistory = "Full-bright Zone Audit slice generated outside character play for placement and obstruction inspection.";
            SectorGenerationTraceAuthority.begin();
            try { w.generate(); }
            finally { auditTraceSteps = SectorGenerationTraceAuthority.end(); }
            if (auditTraceSteps == null) auditTraceSteps = new ArrayList<>();
            if (auditTraceSteps.isEmpty()) auditTraceSteps.add(new SectorGenerationTraceAuthority.Step(0, "FINAL", "Final generated world captured without intermediate trace records.", Math.max(0, w.w/2), Math.max(0, w.h/2), false, SectorGenerationTraceAuthority.snapshot(w)));
            auditTracePlaying = true;
            auditTraceIndex = 0;
            auditTraceLastAdvance = System.currentTimeMillis();
            auditWorld = auditTraceSteps.get(0).world;
            auditFindingIndex = 0;
            refreshSectorAuditSnapshot(auditSettings, previousSeed, "trace start: " + reason);
            DebugLog.audit("ZONE_AUDIT", auditReport);
            logEvent("Zone audit trace generated: " + w.zoneType.label + " steps=" + auditTraceSteps.size() + " finalRooms=" + w.rooms.size() + ".");
        } finally {
            WorldGenerationApi.setActiveSettings(previousSettings);
        }
        repaint();
    }

    void refreshSectorAuditSnapshot(WorldSetupSettings auditSettings, long previousSeed, String reason) {
        if (auditWorld == null) return;
        auditSnapshot = SectorAuditRuntimeAuthority.analyze(auditWorld, auditSettings, previousSeed, auditSeed);
        SectorGenerationTraceAuthority.Step step = currentAuditTraceStep();
        String traceLine = step == null ? "trace=none" : step.line(auditTraceSteps == null ? 0 : auditTraceSteps.size());
        auditReport = traceLine + " | " + auditSnapshot.summary + " reason=" + reason;
        if (step != null) { auditCursorX = step.x; auditCursorY = step.y; }
        else {
            SectorAuditRuntimeAuthority.AuditFinding firstFinding = auditSnapshot.selected(0);
            if (firstFinding != null) { auditCursorX = firstFinding.x; auditCursorY = firstFinding.y; }
            else { auditCursorX = Math.max(0, auditWorld.w / 2); auditCursorY = Math.max(0, auditWorld.h / 2); }
        }
    }

    SectorGenerationTraceAuthority.Step currentAuditTraceStep() {
        if (auditTraceSteps == null || auditTraceSteps.isEmpty()) return null;
        auditTraceIndex = Math.max(0, Math.min(auditTraceSteps.size() - 1, auditTraceIndex));
        return auditTraceSteps.get(auditTraceIndex);
    }

    void applyAuditTraceStep(String reason) {
        SectorGenerationTraceAuthority.Step step = currentAuditTraceStep();
        if (step == null || step.world == null) return;
        auditWorld = step.world;
        WorldSetupSettings auditSettings = auditSettings();
        refreshSectorAuditSnapshot(auditSettings, auditSeed, reason);
        repaint();
    }

    void toggleAuditTracePlayback() {
        if (auditTraceSteps == null || auditTraceSteps.isEmpty()) { repaint(); return; }
        auditTracePlaying = !auditTracePlaying;
        if (auditTracePlaying && auditTraceIndex >= auditTraceSteps.size() - 1) auditTraceIndex = 0;
        auditTraceLastAdvance = System.currentTimeMillis();
        applyAuditTraceStep(auditTracePlaying ? "trace playback" : "trace paused");
    }

    void stepAuditTrace(int delta) {
        if (auditTraceSteps == null || auditTraceSteps.isEmpty()) { repaint(); return; }
        auditTracePlaying = false;
        auditTraceIndex = Math.max(0, Math.min(auditTraceSteps.size() - 1, auditTraceIndex + delta));
        applyAuditTraceStep("manual trace step");
    }

    void advanceAuditTracePlaybackIfNeeded() {
        if (!auditTracePlaying || auditTraceSteps == null || auditTraceSteps.isEmpty()) return;
        long now = System.currentTimeMillis();
        if (now - auditTraceLastAdvance < 1000L) return;
        auditTraceLastAdvance = now;
        if (auditTraceIndex < auditTraceSteps.size() - 1) {
            auditTraceIndex++;
            applyAuditTraceStep("automatic one-second trace advance");
        } else {
            auditTracePlaying = false;
        }
    }

    void cycleAuditZoneType(int delta) { auditZoneDropdownOpen = false; setAuditZoneTypeIndex(auditZoneTypeIndex + delta); }
    void cycleAuditZoneSize() { auditZoneSizeIndex = (auditZoneSizeIndex + 1) % WorldSetupSettings.ZONE_SIZE.length; regenerateSectorAuditWorld("cycle zone size"); }
    void cycleAuditZoneDensity() { auditZoneDensityIndex = (auditZoneDensityIndex + 1) % WorldSetupSettings.ZONE_DENSITY.length; regenerateSectorAuditWorld("cycle zone density"); }
    void toggleAuditSewerLayer() { auditSewerLayer = !auditSewerLayer; regenerateSectorAuditWorld("toggle sewer layer"); }
    void rerollSectorAudit() { regenerateSectorAuditWorld("reroll zone audit"); }
    void cycleAuditOverlay() { auditOverlayMode = Math.floorMod(auditOverlayMode + 1, SectorAuditRuntimeAuthority.OVERLAY_LABELS.length); repaint(); }
    void jumpAuditFinding(int delta) {
        if (auditSnapshot == null || auditSnapshot.findings.isEmpty() || auditWorld == null) { repaint(); return; }
        auditFindingIndex = Math.floorMod(auditFindingIndex + delta, auditSnapshot.findings.size());
        SectorAuditRuntimeAuthority.AuditFinding f = auditSnapshot.selected(auditFindingIndex);
        if (f != null) {
            auditCursorX = Math.max(0, Math.min(auditWorld.w - 1, f.x));
            auditCursorY = Math.max(0, Math.min(auditWorld.h - 1, f.y));
        }
        repaint();
    }

    void moveAuditCursor(int dx, int dy) {
        if (auditWorld == null) return;
        auditCursorX = Math.max(0, Math.min(auditWorld.w - 1, auditCursorX + dx));
        auditCursorY = Math.max(0, Math.min(auditWorld.h - 1, auditCursorY + dy));
        repaint();
    }

